+#[test]
+fn t96_26_waiver_types_defined() {
+    init_test("t96_26_waiver_types_defined");
+
+    let doc = load_policy();
+
+    for wv in ["WV-01", "WV-02", "WV-03", "WV-04"] {
+        test_section!(wv);
+        assert!(doc.contains(wv), "missing waiver type: {wv}");
+    }
+
+    test_complete!("t96_26_waiver_types_defined");
+}
